var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"원정이라고?","JPN":"遠征？","ENG":"An expedition?","TWN":"調查？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"응. 관측대를 개선하면서 탐측범위를 넓혔는데, 먼 곳에서 아주 특이한 에너지를 발견했거든.","JPN":"そうよ。観測台を改良して探測の範囲を広げていたら、遠くのほうでとても変わったエネルギーを発見したわ。","ENG":"Yes. After improving the observation range in the observatory, we discovered a strange energy from afar.","TWN":"嗯，改善觀測台擴大探測範圍後，在遠處發現到非常特殊的能量。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 특이한 에너지라는 게 어떤 거죠?","JPN":"その変わったエネルギーって、どんなものなんですか？","ENG":"What do you mean by a strange energy?","TWN":"那個特殊的能量是什麼？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"우리도 정확히는 몰라.","JPN":"それはアタシたちにも詳しくはわからない。","ENG":"We are unsure.","TWN":"我們也不太清楚。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 그 파형은 그루터기가 발산하는 것과 닮아 있어.","JPN":"でも、その波形は切り株から出ているものと似ているの。","ENG":"However, the waveforms resemble similar patterns to those of the one emitted from the Stump.","TWN":"但那個波形和木墩發出的很相似。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"황금나무와 같은 파형이라면…?","JPN":"黄金の木と同じ波形って……","ENG":"If it's the same waveform as the Golden Tree...","TWN":"如果是和黃金樹一樣的波形…？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"설마 황금가지가 거기에 있는 거야?","JPN":"まさか、黄金の枝がそこにあるの？","ENG":"then does that mean there's a Golden Branch over there?","TWN":"難道那裡有金枝？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"가능성은 높지만, 직접 보기 전엔 단정지을 수 없어.","JPN":"その可能性は高いけど、直接見るまでは断定できないわ。","ENG":"It is possible, but we cannot be certain until we see it for ourselves.","TWN":"可能性很高，但在親眼看到之前不能確定。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러니 두 사람이 확인을 위해 그곳에 다녀와줬으면 해.","JPN":"だから、二人が確認のためにそこに行ってきてほしいの。","ENG":"So, I want you two to go over there to confirm it.","TWN":"所以希望你們二個人去那裡確認一下。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야. 늘 하던 일이네.","JPN":"なんだよ。いつもやってることじゃん。","ENG":"What? That's just doing our jobs.","TWN":"什麼嘛，還是老樣子。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그런 거라면 우리만 따로 부를 필요 없이, 정식으로 조사단을 움직여도 되지 않아?","JPN":"それならあたしたちだけを呼ばなくても、正式に調査団に動いてもらえばいいんじゃない？","ENG":"Why did you secretly summon us when you could've officially requested the survey corps?","TWN":"那樣的話，不用單獨叫我們，正式動用調查團不就行了嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이번 일은 조금 달라.","JPN":"今度の仕事は少し違うわ。","ENG":"This one is a bit different.","TWN":"這次的事情有些不同。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"거리가 아주 멀어서, 낙원문의 전송기능을 이용할 생각이니까.","JPN":"とても遠くて、楽園の門の伝送機能を利用するつもりだから。","ENG":"It is extremely far, so I am intending on using Avalon's Gate's transfer technology.","TWN":"因為距離非常遠，所以打算利用樂園門的傳送功能。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐…? 진심이야?","JPN":"は……？　本気？","ENG":"What...? Are you serious?","TWN":"什…？你是認真的嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그걸 가동하려면 귀한 적철을 연료로 써야 하잖아!","JPN":"あれを稼働させるには、貴重な赤鉄を燃料に使わないとダメでしょ！","ENG":"But you'll have to use precious Violarite as fuel to operate that!","TWN":"啟動那個需要用珍貴的赤鐵作為燃料欸！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래서 두 사람만 보내는 거야.","JPN":"だから二人だけ行かせるのよ。","ENG":"That is why I am only sending the two of you.","TWN":"所以才只派你們二個人去。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"며칠 사이에 특이 에너지의 신호가 눈에 띄게 약해졌어. 마차로 움직였다간 그 정체를 눈으로 확인하기도 전에 사라지고 말겠지.","JPN":"ここ数日で特異エネルギーの信号はとても弱くなったわ。馬車で動いたら、正体を確認する前に消えてしまう。","ENG":"The unusual energy's signal has become noticeably weaker in the past few days. I assume that it will disappear and you will not be able to confirm what it is if you mobilize by carriage.","TWN":"幾天之間，奇怪能量的訊號明顯減弱了。如果坐馬車去的話，還沒等確認到它的真面目就會消失。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그게 만약 황금가지라면, 그루터기에 도움이 되는 거겠죠?","JPN":"もしそれが黄金の枝なら、切り株の役に立つんですよね？","ENG":"But if it's really a Golden Branch, it'll help the Stump, right?","TWN":"如果那是金枝的話，對木墩會有幫助的吧？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그야 당연하지! 황금가지는 죽은 황금나무를 살리고 역병을 막아주는 힘이라고!","JPN":"当たり前でしょ！　黄金の枝は死んだ黄金の木を再生させ、疫病を防いでくれる力なの！","ENG":"Of course, it will! The Golden Branch is the power that can revive the dead Golden Tree and prevent the plague!","TWN":"那當然！金枝有復活枯死的黃金樹和阻止瘟疫的力量！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうよ。","ENG":"She is correct.","TWN":"沒錯。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"만에 하나, 온전한 황금가지를 구할 수만 있다면 우리 염원을 실현할 수도 있어.","JPN":"万が一、完全な黄金の枝を手に入れることができるなら、アタシたちの願いを実現することができるかもしれないわ。","ENG":"If we are able to acquire a Golden Branch that is fully intact, then we will be able to make our dream come true.","TWN":"如果能找到完整的金枝，我們的願望就可以實現了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"낙원으로의 이주를 말이야.","JPN":"楽園への移住を。","ENG":"Migrating to the Promised Land.","TWN":"那就是移居到樂園。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그런 중요한 일을 제가 맡아도 되는 걸까요?","JPN":"そんな重要な仕事を、私が引き受けてもいいのでしょうか？","ENG":"Are you sure you want me to take on such an important task?","TWN":"這麼重要的事，交給我真的可以嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"알고 계시겠지만 저는…","JPN":"ご存じだと思いますが、私は……","ENG":"As you might already know, I'm–","TWN":"你知道的，我…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"괜찮아.","JPN":"構わないわ。","ENG":"It is fine.","TWN":"無所謂。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"난 네가 쓸모만 있다면, 그 정체가 뭐든 상관없으니까.","JPN":"アタシはアナタが役立つ存在なら、その正体が何だろうと関係ない。","ENG":"I do not care what you are, as long as you are useful to me.","TWN":"只要你能派上用場，我不在乎你是什麼身份。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…네.","JPN":"……はい。","ENG":"...Okay.","TWN":"…好。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"망설일 것도 없네. 당장 가자.","JPN":"迷うまでもないね。今すぐ行こう。","ENG":"There's no time to waste. Let's go right now.","TWN":"沒什麼好猶豫的，我們馬上出發。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"황금가지를 찾아서 돌아오면, 그땐 모두가 루를 인정할 수밖에 없을걸?","JPN":"黄金の枝を持って帰ってきたら、その時にはみんなルーのことを認めるしかないはずよ。","ENG":"I'm sure everyone will have to acknowledge you if you come back with a Golden Branch.","TWN":"找到金枝以後，大家就都會認可你了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};